      "description": "Get the status and text of a transcript by ID",
      "requiresWrite": false,
      "endpoint": {
        "method": "GET",
        "url": "https://api.assemblyai.com/v2/transcript/{transcript_id}",
        "params": {
          "transcript_id": {
            "type": "string",
            "in": "path",
            "description": "ID of the transcript to fetch",
            "required": true,
          },
        },
      },
