      "name": "ATTIO_CLIENT_SECRET",
      "description": "Attio OAuth Client Secret",
      "required": true,
      "sensitive": true,
      "docsUrl": "https://docs.attio.com/rest-api/tutorials/connect-an-app-through-oauth",
