    "setupGuide": {
      "title": "Chargebee API Setup",
      "steps": [{
        "step": 1,
        "title": "Create a Chargebee account",
        "description":
          "Sign up at https://www.chargebee.com. A test site (e.g. acme-test.chargebee.com) is created automatically when you sign up — use it for development before switching to your live site.",
      }, {
        "step": 2,
        "title": "Create an API key",
        "description":
          "In the Chargebee app go to Settings → Configure Chargebee → API Keys and Webhooks → API Keys, click Add an API Key, choose Full-Access Key, and copy the generated key.",
      }, {
        "step": 3,
        "title": "Set environment variables",
        "description":
          "Add CHARGEBEE_API_KEY (the key from step 2) and CHARGEBEE_SITE (your site subdomain, e.g. acme-test) to your .env. Leave CHARGEBEE_API_PASSWORD unset or empty — Chargebee uses the API key as the HTTP Basic username with an empty password.",
      }, {
        "step": 4,
        "title": "Verify access",
        "description":
          "Run List Subscriptions with site set to your CHARGEBEE_SITE value. All requests go to https://{site}.chargebee.com/api/v2 over HTTPS.",
      }],
      "notes": [
        "API keys are environment-specific: your test site and live site have separate keys and separate site subdomains.",
        "Chargebee filters use bracket operators in query parameter names, e.g. status[is]=active or email[is]=jane@example.com.",
        "List endpoints paginate with an opaque next_offset string — pass it back as the offset parameter to fetch the next page.",
      ],
      "documentation": "https://apidocs.chargebee.com/docs/api",
    },
