    "setupGuide": {
      "title": "CleverReach setup",
      "steps": [{
        "step": 1,
        "title": "Create a CleverReach account",
        "description":
          "Sign up at cleverreach.com — the free Lite plan (up to 250 recipients) is enough for development and testing.",
      }, {
        "step": 2,
        "title": "Create an OAuth app",
        "description":
          "In your CleverReach account go to Account > Extras > REST API and create an OAuth app. Note the Client ID and Client Secret it contains, and register your redirect (callback) URL.",
      }, {
        "step": 3,
        "title": "Store the credentials and connect",
        "description":
          "Set CLEVERREACH_CLIENT_ID and CLEVERREACH_CLIENT_SECRET, then complete the OAuth authorization-code flow: the user logs in at the CleverReach consent screen and the returned code is exchanged for an access token.",
      }],
      "notes": [
        "The authorization request must include the extra parameter grant=basic alongside client_id, response_type=code, and redirect_uri.",
        "Access tokens are long-lived (expires_in in the token response, for example 31536000 seconds) and a refresh_token is issued for renewing them via grant_type=refresh_token.",
        "Each OAuth token is scoped to the CleverReach account that authorized the app; the app's permissions are configured on the OAuth app itself rather than via per-request scopes.",
      ],
      "documentation": "https://developers.cleverreach.com/",
    },
