    "setupGuide": {
      "title": "Gorgias setup",
      "steps": [{
        "step": 1,
        "title": "Get a Gorgias account",
        "description":
          "Sign up at https://www.gorgias.com — new accounts start with a free trial you can use for testing. Note your account subdomain (the 'acme' in acme.gorgias.com).",
      }, {
        "step": 2,
        "title": "Create a REST API key",
        "description":
          "In your Gorgias dashboard, open Settings → REST API. Copy the Base API URL (https://<your-domain>.gorgias.com/api), your username (your account email), and create/copy the API key (password).",
      }, {
        "step": 3,
        "title": "Store the credentials",
        "description":
          "Add GORGIAS_USERNAME=<your account email>, GORGIAS_API_KEY=<your API key>, and GORGIAS_ACCOUNT_DOMAIN=<your subdomain> to your .env file. The API uses HTTP Basic auth with email as username and API key as password.",
      }, {
        "step": 4,
        "title": "Verify access",
        "description":
          "Run the List Tickets tool with your account subdomain as accountDomain. You should get back a page of tickets (empty data array on a fresh account).",
      }],
      "notes": [
        "Every tool takes an accountDomain path parameter — pass the value stored in GORGIAS_ACCOUNT_DOMAIN",
        "API keys inherit the permissions of the user they belong to; create the key from an account with access to the tickets you need",
        "Creating a message with channel 'email' actually emails the customer — use channel 'internal-note' for private notes",
      ],
      "documentation": "https://developers.gorgias.com/reference",
    },
