    "setupGuide": {
      "title": "Paddle setup",
      "steps": [{
        "step": 1,
        "title": "Create a Paddle account",
        "description":
          "Sign up for a free sandbox account at https://sandbox-login.paddle.com/signup to test against simulated data, or use your live account at https://login.paddle.com.",
      }, {
        "step": 2,
        "title": "Create an API key",
        "description":
          "In the Paddle dashboard, go to Paddle > Developer tools > Authentication, open the API keys tab, and select New API key. Name it, assign the permissions you need (e.g. read for products, prices, customers, transactions, subscriptions; write for products), and set an expiry (default 90 days, maximum 1 year). The key is shown only once - store it securely.",
      }, {
        "step": 3,
        "title": "Configure the environment variable",
        "description":
          "Set PADDLE_API_KEY to your key. Sandbox keys start with pdl_sdbx_apikey_ and live keys with pdl_live_apikey_.",
      }],
      "notes": [
        "Sandbox uses a separate host: replace api.paddle.com with sandbox-api.paddle.com when working with a sandbox key. Keys are environment-specific and do not work across environments.",
        "List endpoints return a data array plus meta pagination info; follow meta.pagination.next or pass the last ID as the after cursor.",
        "Transactions are capped at 30 results per page; other entities support larger pages.",
        "API keys expire (maximum 1 year), so rotate them before expiry to avoid outages.",
      ],
      "documentation": "https://developer.paddle.com/api-reference/overview",
    },
