      "requiredApis": [{
        "name": "eTrusted API credentials",
        "enableUrl": "https://app.etrusted.com/",
      }],
      "additionalParams": { "audience": "https://api.etrusted.com" },
      "docsUrl": "https://developers.etrusted.com/docs/authentication",
